  @Entry
  @Component
  struct CircularRevealExample {
    @State circleRadius: number = 280; // Initial maxCornerDistance

    build() {
      Column() {
        Image($r('app.media.old_snapshot')) // Your overlay Image
          .width('100%').height('100%')
          .clipShape(new CircleShape({ width: this.circleRadius, height: this.circleRadius }))
          .onClick(() => {
            this.getUIContext().animateTo({ duration: 500 }, () => {
              this.circleRadius = 0; // Animate to 0 to reveal new theme
            });
          })
      }
    }
  }
